// ==UserScript==
// @name         WebScope Keeper v4.3.20
// @namespace    http://tampermonkey.net/
// @version      4.3.20
// @description  Export Quality Analysis Report with Confidence Scores and Recommendations
// @author       WebScope Team
// @match        *://*/*
// @grant        GM_setClipboard
// @grant        GM_addStyle
// @grant        GM_getValue
// @grant        GM_setValue
// @grant        GM_xmlhttpRequest
// @connect      localhost
// @connect      127.0.0.1
// @connect      149.102.159.192
// @connect      *
// @run-at       document-end
// ==/UserScript==

(function() {
    'use strict';

    console.log('🔓 WebScope Keeper v4.3.20: Export Quality Analysis Report');

    // First-run security disclaimer
    if (!GM_getValue('security_disclaimer_accepted', false)) {
        const accepted = confirm(
            '⚠️ WEBSCOPE SECURITY TESTING TOOL - AUTHORIZED USE ONLY ⚠️\n\n' +
            'This tool is designed for AUTHORIZED security testing only.\n\n' +
            '✅ USE ONLY ON:\n' +
            '  • Your own applications\n' +
            '  • Systems you have written permission to test\n' +
            '  • Test/development environments\n\n' +
            '❌ NEVER USE ON:\n' +
            '  • Third-party websites without authorization\n' +
            '  • Production systems without explicit permission\n' +
            '  • Banking, healthcare, or financial sites\n\n' +
            '📋 YOU ARE RESPONSIBLE FOR:\n' +
            '  • Obtaining proper authorization\n' +
            '  • Compliance with laws (GDPR, CCPA, HIPAA, etc.)\n' +
            '  • Securing any captured data\n\n' +
            'By clicking OK, you confirm:\n' +
            '  ✓ You have authorization to test this application\n' +
            '  ✓ You understand this is a professional security tool\n' +
            '  ✓ You accept responsibility for your use\n\n' +
            'Read SECURITY_DISCLAIMER.md for full terms.\n\n' +
            'Click OK to accept and continue, Cancel to abort.'
        );

        if (!accepted) {
            console.log('❌ WebScope: Security disclaimer not accepted. Extension will not activate.');
            return; // Exit immediately if user declines
        }

        GM_setValue('security_disclaimer_accepted', true);
        console.log('✅ WebScope: Security disclaimer accepted');
    }

    // Authentication - stored with GM_getValue/GM_setValue
    let API_KEY = GM_getValue('webscope_api_key', '');
    let isAuthenticated = Boolean(API_KEY);

    // ============================================================================
    // DYNAMIC SERVER CONFIGURATION (NO HARDCODED IPs)
    // ============================================================================

    // Auto-detect server from current page origin OR document.referrer
    function autoDetectServer() {
        // METHOD 1: Try to detect from current page (if running on WebScope server)
        const currentOrigin = window.location.origin;

        // Check if we're on a likely WebScope server page
        if (currentOrigin.includes('7443') || currentOrigin.includes('7444') ||
            currentOrigin.includes('7500') || window.location.pathname.includes('webscope')) {
            return {
                address: window.location.hostname,
                port: window.location.port || (window.location.protocol === 'https:' ? '443' : '80'),
                https: window.location.protocol === 'https:'
            };
        }

        // METHOD 2: Try to detect from document.referrer (where script was downloaded from)
        if (document.referrer) {
            try {
                const referrerUrl = new URL(document.referrer);
                // Check if referrer is a WebScope server
                if (referrerUrl.port === '7443' || referrerUrl.port === '7444' ||
                    referrerUrl.port === '7500' || referrerUrl.pathname.includes('webscope')) {
                    return {
                        address: referrerUrl.hostname,
                        port: referrerUrl.port || (referrerUrl.protocol === 'https:' ? '443' : '80'),
                        https: referrerUrl.protocol === 'https:'
                    };
                }
            } catch (e) {
                console.warn('WebScope: Could not parse referrer URL:', e);
            }
        }

        // No auto-detection possible - must be configured by user
        return null;
    }

    // Initialize server configuration
    let serverConfig = GM_getValue('webscope_server_config', null);
    let serverConfigured = Boolean(serverConfig);

    // If not configured, try auto-detection
    if (!serverConfigured) {
        const detected = autoDetectServer();
        if (detected) {
            serverConfig = detected;
            GM_setValue('webscope_server_config', serverConfig);
            serverConfigured = true;
            console.log('✅ WebScope: Auto-detected server from',
                       document.referrer ? 'download page' : 'current page',
                       ':', detected.address + ':' + detected.port);
        }
    }

    // Server configuration variables (NO DEFAULTS - must be configured)
    let SERVER_ADDRESS = serverConfig ? serverConfig.address : null;
    let SERVER_PORT = serverConfig ? serverConfig.port : null;
    let USE_HTTPS = serverConfig ? serverConfig.https : false;

    function getWebScopeAPI() {
        if (!SERVER_ADDRESS || !SERVER_PORT) {
            return null; // Server not configured
        }
        const protocol = USE_HTTPS ? 'https' : 'http';
        return `${protocol}://${SERVER_ADDRESS}:${SERVER_PORT}`;
    }

    const PUBLISH_ENDPOINT = '/api/extension/publish';

    // State
    let isActive = true;  // Changed: Auto-open by default
    let isWatchMode = false;
    let capturedFields = [];
    let sessionId = null;
    let isExpanded = GM_getValue('webscope_expanded', false);  // Resize state

    // Position state - remember last position
    let panelPosition = {
        left: GM_getValue('webscope_pos_left', null),
        top: GM_getValue('webscope_pos_top', null)
    };

    // Session storage keys
    const STORAGE_PREFIX = 'webscope_keeper_';
    const SESSION_KEY = STORAGE_PREFIX + 'session';
    const FIELDS_KEY = STORAGE_PREFIX + 'fields';
    const WATCH_MODE_KEY = STORAGE_PREFIX + 'watch_mode';

    // Keeper Colors
    const KEEPER_YELLOW = '#FFD700';
    const KEEPER_GOLD = '#FFC107';
    const KEEPER_BLACK = '#000000';
    const KEEPER_DARK = '#1a1a1a';
    const KEEPER_GRAY = '#2d2d2d';

    // Wait for body
    function init() {
        if (!document.body) {
            setTimeout(init, 100);
            return;
        }

        console.log('🔐 Initializing WebScope Keeper v4.3.20...');
        console.log('✨ AUTO-CONFIG: Server auto-detected from download location');
        console.log('🌐 Server Status:', serverConfigured ?
                   `✅ ${SERVER_ADDRESS}:${SERVER_PORT}` :
                   '⚠️ Not configured - will auto-detect or require manual setup');
        console.log('🔑 Authentication:', isAuthenticated ? '✅ Token configured' : '⚠️ Token required');

        // Restore session if exists
        restoreSession();

        addStyles();
        createUI();

        console.log('✅ WebScope Keeper v4.3.20 ready (Export Quality Reports)!');
        if (isWatchMode) {
            console.log('🔄 Watch Mode: Active (session restored)');
            console.log('📊 Captured fields:', capturedFields.length);
        }

        // SIMPLIFIED AUTHENTICATION: If server is configured but no API key, prompt ONLY for API key
        if (serverConfigured && !isAuthenticated) {
            setTimeout(() => {
                promptForAPIKey();
            }, 500);
        }
    }

    // Simplified API Key Prompt (server already configured)
    function promptForAPIKey() {
        const apiKey = prompt(
            `🔐 WebScope Keeper - API Token Required\n\n` +
            `Server: ${SERVER_ADDRESS}:${SERVER_PORT}\n\n` +
            `Please enter your API token:\n` +
            `(Get your token from the WebScope UI Admin panel)`
        );

        if (apiKey && apiKey.trim()) {
            API_KEY = apiKey.trim();
            GM_setValue('webscope_api_key', API_KEY);
            isAuthenticated = true;
            console.log('✅ WebScope: API token configured');
            alert(`✅ API Token Saved!\n\nYou can now use WebScope Keeper with:\n${getWebScopeAPI()}`);
            renderPanel();
        } else if (apiKey !== null) {
            alert('⚠️ No API token entered.\n\nYou can configure it later via Settings.');
        }
    }

    // Save session state
    function saveSession() {
        try {
            sessionStorage.setItem(WATCH_MODE_KEY, isWatchMode ? '1' : '0');
            sessionStorage.setItem(SESSION_KEY, sessionId || Date.now().toString());
            sessionStorage.setItem(FIELDS_KEY, JSON.stringify(capturedFields.map(f => ({
                name: f.name,
                id: f.id,
                type: f.type,
                placeholder: f.placeholder,
                selector: f.selector,
                selectorOptions: f.selectorOptions,
                selectedSelector: f.selectedSelector,
                category: f.category,
                interactions: f.interactions,
                text: f.text
            }))));
        } catch (e) {
            console.warn('Could not save session:', e);
        }
    }

    // Restore session state
    function restoreSession() {
        try {
            const watchMode = sessionStorage.getItem(WATCH_MODE_KEY);
            const fieldsData = sessionStorage.getItem(FIELDS_KEY);
            sessionId = sessionStorage.getItem(SESSION_KEY);

            if (watchMode === '1') {
                isWatchMode = true;

                if (fieldsData) {
                    const savedFields = JSON.parse(fieldsData);
                    capturedFields = savedFields;
                }

                // Auto-enable watch mode
                enableWatchMode();
            }
        } catch (e) {
            console.warn('Could not restore session:', e);
        }
    }

    // Clear session
    function clearSession() {
        try {
            sessionStorage.removeItem(WATCH_MODE_KEY);
            sessionStorage.removeItem(SESSION_KEY);
            sessionStorage.removeItem(FIELDS_KEY);
            sessionId = null;
        } catch (e) {
            console.warn('Could not clear session:', e);
        }
    }

    // Add styles - ENHANCED with better floating experience + HIDDEN TOGGLE
    function addStyles() {
        GM_addStyle(`
            #ws-toggle {
                position: fixed !important;
                top: 10px !important;
