            .ws-content {
                flex: 1 !important;
                overflow-y: auto !important;
                padding: 14px !important;
                background: ${KEEPER_BLACK} !important;
                color: #fff !important;
            }
            .ws-content::-webkit-scrollbar { width: 8px !important; }
            .ws-content::-webkit-scrollbar-track {
                background: ${KEEPER_BLACK} !important;
                border-radius: 4px !important;
            }
