                overflow-y: auto !important;
                white-space: pre-wrap !important;
                word-break: break-all !important;
            }
            .ws-rbi-preview::-webkit-scrollbar { width: 6px !important; }
            .ws-rbi-preview::-webkit-scrollbar-thumb {
