                    outline-width: 5px;
                    outline-offset: 5px;
                }
            }
        `);
    }

    // ============================================
    // AUTHENTICATION FUNCTIONS
    // ============================================

    function setupAPIKey() {
        const key = prompt(
            '🔑 Enter your WebScope API Key\n\n' +
            'Get your key from: WebScope UI → Settings → API Keys → Create API Key\n\n' +
            'Key format: ws_XXXXXXXXXX...'
        );

        if (key && key.startsWith('ws_')) {
            GM_setValue('webscope_api_key', key);
            API_KEY = key;
            isAuthenticated = true;
            alert('✅ API Key saved! You can now publish findings to WebScope.');
            if (isActive) renderPanel();
            return true;
        } else if (key) {
            alert('❌ Invalid API key format. Must start with ws_');
            return false;
        }
        return false;
    }

    function clearAPIKey() {
        if (confirm('Clear saved API key?')) {
            GM_setValue('webscope_api_key', '');
            API_KEY = '';
            isAuthenticated = false;
            alert('✅ API key cleared. Setup again to publish findings.');
            if (isActive) renderPanel();
        }
    }

    async function publishToWebScope() {
        // Check if server is configured first
        if (!serverConfigured || !getWebScopeAPI()) {
            const configure = confirm(
                '⚠️ SERVER NOT CONFIGURED!\n\n' +
                'No WebScope server has been configured yet.\n\n' +
                'Click OK to configure server settings now.'
            );
            if (configure) {
                showSettings();
            }
            return false;
        }

        if (!isAuthenticated) {
            alert('⚠️ API key required to publish!\n\nClick "🔑 Setup API Key" button first.');
            return false;
        }

        if (capturedFields.length === 0) {
            alert('⚠️ No fields captured yet!\n\nWatch Mode is active - interact with form fields to capture them.');
            return false;
        }

        try {
            console.log('📤 Publishing findings to WebScope...');

            const fieldsObject = {
                username: [],
                password: [],
                submit: [],
                other: []
            };

            capturedFields.forEach(f => {
                const fieldData = {
                    name: f.name,
                    id: f.id,
                    type: f.type,
                    selector: f.selector,
                    category: f.category || 'other',
                    placeholder: f.placeholder
                };

                if (f.category === 'username' || f.type === 'email' || f.type === 'text') {
                    fieldsObject.username.push(fieldData);
                } else if (f.category === 'password' || f.type === 'password') {
                    fieldsObject.password.push(fieldData);
                } else if (f.category === 'submit' || f.type === 'submit') {
                    fieldsObject.submit.push(fieldData);
                } else {
                    fieldsObject.other.push(fieldData);
                }
            });

            Object.keys(fieldsObject).forEach(key => {
                if (fieldsObject[key].length === 0) {
                    delete fieldsObject[key];
                }
            });

            const data = {
                url: window.location.href,
                fields: fieldsObject,
                metadata: {
                    detected_by: 'webscope_keeper_v4.2.8',
                    page_title: document.title,
                    detection_method: 'watch_mode',
                    watch_mode: true,
                    user_agent: navigator.userAgent,
                    timestamp: new Date().toISOString()
                },
                confidence_score: 1.0,
                user_validated: true,
                watch_mode: true
            };

            return new Promise((resolve, reject) => {
                GM_xmlhttpRequest({
                    method: 'POST',
                    url: `${getWebScopeAPI()}${PUBLISH_ENDPOINT}`,
                    headers: {
                        'Content-Type': 'application/json',
                        'X-API-Key': API_KEY
                    },
                    data: JSON.stringify(data),
                    timeout: 10000,
                    onload: function(response) {
                        if (response.status === 0) {
                            alert(
                                '❌ CONNECTION BLOCKED!\n\n' +
                                'Check Tampermonkey permissions and WebScope status.'
                            );
                            resolve(false);
                            return;
                        }

                        if (response.status >= 200 && response.status < 300) {
                            console.log('✅ Published to WebScope successfully');
                            alert('✅ Successfully published to WebScope!\n\n' + capturedFields.length + ' fields saved.');
                            resolve(true);
                            return;
                        }

                        if (response.status === 401) {
                            console.error('❌ Authentication failed');
                            isAuthenticated = false;
                            alert('❌ API key invalid or expired!\n\nPlease setup a new key.');
                            renderPanel();
                            resolve(false);
                            return;
                        }

                        console.error('❌ Publish failed:', response.status, response.responseText);
                        alert('❌ Publish failed: ' + response.status);
                        resolve(false);
                    },
                    onerror: function(error) {
                        console.error('❌ Publish error:', error);
                        alert('❌ Network error! Check WebScope status.');
                        reject(error);
                    },
                    ontimeout: function() {
                        console.error('❌ Request timeout');
                        alert('❌ Request timeout! WebScope took too long to respond.');
                        resolve(false);
                    }
                });
            });
        } catch (e) {
            console.error('❌ Publish error:', e);
            alert('❌ Publish failed: ' + e.message);
            return false;
        }
    }

