    // FLUID draggable - Using Weekly Reports offset-based algorithm
    // CRITICAL: Must reinitialize after each renderPanel() call since innerHTML is replaced
    let dragState = {
        isDragging: false,
        currentX: 0,
        currentY: 0,
        initialX: 0,
        initialY: 0
    };

    function makeDraggable(panel) {
        const header = panel.querySelector('.ws-header');
        if (!header) {
            console.error('❌ WebScope: Header not found for dragging!');
            return;
        }

        console.log('✅ Perfect FLUID dragging enabled (Weekly Reports proven algorithm)');

        // Use shared drag state to avoid closure issues with multiple calls
        const handleMouseDown = function(e) {
            // Don't drag if clicking buttons or interactive elements
            if (e.target.tagName === 'BUTTON' ||
                e.target.tagName === 'SELECT' ||
                e.target.closest('button') ||
                e.target.closest('select')) {
                return;
            }

            dragState.isDragging = true;
            panel.classList.add('dragging');
            dragState.initialX = e.clientX - panel.offsetLeft;
            dragState.initialY = e.clientY - panel.offsetTop;
        };

        const handleMouseMove = function(e) {
            if (dragState.isDragging) {
                const isInteractiveElement = e.target.tagName === 'INPUT' ||
                                            e.target.tagName === 'TEXTAREA' ||
                                            e.target.tagName === 'SELECT';
                if (!isInteractiveElement) {
                    e.preventDefault();
                }
                dragState.currentX = e.clientX - dragState.initialX;
                dragState.currentY = e.clientY - dragState.initialY;
                panel.style.left = dragState.currentX + 'px';
                panel.style.top = dragState.currentY + 'px';
                panel.style.right = 'auto';
            }
        };

        const handleMouseUp = function() {
            if (dragState.isDragging) {
                dragState.isDragging = false;
                panel.classList.remove('dragging');
                panelPosition.left = panel.offsetLeft;
                panelPosition.top = panel.offsetTop;
                GM_setValue('webscope_pos_left', panelPosition.left);
                GM_setValue('webscope_pos_top', panelPosition.top);
            }
        };

        // Remove old listeners before adding new ones
        header.removeEventListener('mousedown', handleMouseDown);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);

        // Add listeners
        header.addEventListener('mousedown', handleMouseDown);
        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    }

    // Toggle panel
