    // Attach event listeners
    function attachEventListeners() {
        const closeBtn = document.getElementById('ws-close-btn');
        if (closeBtn) {
            closeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                closePanel();
            });
        }

        const settingsBtn = document.getElementById('ws-settings-btn');
        if (settingsBtn) {
            settingsBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                showSettings();
            });
        }

        const resizeBtn = document.getElementById('ws-resize-btn');
        if (resizeBtn) {
            resizeBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                toggleResize();
            });
        }

        const startWatchBtn = document.getElementById('ws-start-watch-btn');
        if (startWatchBtn) {
            startWatchBtn.addEventListener('click', function() {
                setMode(true);
            });
        }

        const stopWatchBtn = document.getElementById('ws-stop-watch-btn');
        if (stopWatchBtn) {
            stopWatchBtn.addEventListener('click', function() {
                setMode(false);
            });
        }

        const exportBtn = document.getElementById('ws-export-btn');
        if (exportBtn) {
            exportBtn.addEventListener('click', exportRBI);
        }

        const endSessionBtn = document.getElementById('ws-end-session-btn');
        if (endSessionBtn) {
            endSessionBtn.addEventListener('click', function() {
                exportRBI();
                clearSession();
                disableWatchMode();
                alert('✅ Session ended and exported!');
            });
        }

        const clearBtn = document.getElementById('ws-clear-btn');
        if (clearBtn) {
            clearBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                e.preventDefault();
                console.log('🗑️ Clear button clicked!');
                clearCaptured();
            });
        } else {
            console.warn('⚠️ Clear button not found in DOM!');
        }

        // Add event listeners for smart suggestion clicks
        const suggestions = document.querySelectorAll('.ws-suggestion');
        suggestions.forEach(suggestion => {
            suggestion.addEventListener('click', function(e) {
                e.stopPropagation();
                const fieldIndex = parseInt(this.dataset.fieldIndex);
                const selector = this.dataset.selector;
                const field = capturedFields[fieldIndex];

                if (field) {
                    field.selectedSelector = selector;
                    console.log(`✅ Smart suggestion selected for ${field.name || field.id}:`, selector);
                    saveSession();
                    renderPanel(); // Re-render to show updated selection
                }
            });
        });

        // Add event listeners for "See all options" links
        const showAllLinks = document.querySelectorAll('.ws-show-all-options');
        showAllLinks.forEach(link => {
            link.addEventListener('click', function(e) {
                e.stopPropagation();
                const fieldIndex = parseInt(this.dataset.fieldIndex);
                const field = capturedFields[fieldIndex];

                if (field && field.selectorOptions) {
                    // Show all options in alert for now (could be a modal later)
                    const optionsText = field.selectorOptions.map((opt, idx) =>
                        `${idx + 1}. [${opt.confidence}% ${opt.quality}] ${opt.label}: ${opt.selector}\n   ${opt.description}`
                    ).join('\n\n');

                    alert(`All selector options for "${field.name || field.id}":\n\n${optionsText}\n\nClick a suggestion above to select it.`);
                }
            });
        });

        const setupKeyBtn = document.getElementById('ws-setup-key-btn');
        if (setupKeyBtn) {
            setupKeyBtn.addEventListener('click', function(e) {
                e.stopPropagation();
                showSettings();
            });
        }

        const publishBtn = document.getElementById('ws-publish-btn');
        if (publishBtn) {
            publishBtn.addEventListener('click', publishToWebScope);
        }

        const clearKeyBtn = document.getElementById('ws-clear-key-btn');
        if (clearKeyBtn) {
            clearKeyBtn.addEventListener('click', clearAPIKey);
        }

        // CRITICAL FIX: Re-enable dragging after panel re-render
        // Every time renderPanel() is called, the innerHTML is replaced which destroys event listeners
        // We must re-attach dragging listeners here to ensure dragging always works
        const panel = document.getElementById('ws-panel');
        if (panel) {
            makeDraggable(panel);
        }
    }

