    // Save settings
    function saveSettings() {
        const address = document.getElementById('ws-server-address').value.trim();
        const port = document.getElementById('ws-server-port').value.trim();
        const useHttps = document.getElementById('ws-use-https').checked;

        if (!address) {
            alert('❌ Server address is required!\n\nExample: 192.168.1.100 or webscope.example.com');
            return;
        }

        if (!port || isNaN(port)) {
            alert('❌ Valid port number is required!\n\nExample: 7444 or 7500');
            return;
        }

        // Save settings using new serverConfig object
        serverConfig = {
            address: address,
            port: port,
            https: useHttps
        };

        SERVER_ADDRESS = address;
        SERVER_PORT = port;
        USE_HTTPS = useHttps;
        serverConfigured = true;

        GM_setValue('webscope_server_config', serverConfig);

        console.log('✅ WebScope: Server configuration saved:', serverConfig);

        alert(`✅ Settings saved!\n\nNew API URL: ${getWebScopeAPI()}\n\n💡 Server is now configured dynamically with no hardcoded values!`);

        // Return to main panel
        renderPanel();
        // Dragging is now re-enabled automatically in attachEventListeners()
    }

    // Set mode
    function setMode(watchMode) {
        isWatchMode = watchMode;

        if (isWatchMode) {
            enableWatchMode();
        } else {
            disableWatchMode();
        }

        renderPanel();
        // Dragging is now re-enabled automatically in attachEventListeners()
    }

    // Enable watch mode
    function enableWatchMode() {
        if (!sessionId) {
            capturedFields = [];
            sessionId = Date.now().toString();
        }

        document.addEventListener('focus', trackInteraction, true);
        document.addEventListener('input', trackInteraction, true);
        document.addEventListener('change', trackInteraction, true);
        document.addEventListener('click', trackInteraction, true); // Track button clicks

        saveSession();
        console.log('👁️ Watch mode enabled - Session persists across pages');
    }

    // Disable watch mode
    function disableWatchMode() {
        document.removeEventListener('focus', trackInteraction, true);
        document.removeEventListener('input', trackInteraction, true);
        document.removeEventListener('change', trackInteraction, true);
        document.removeEventListener('click', trackInteraction, true);

        clearSession();
        console.log('👁️ Watch mode disabled - Session cleared');
    }

    // Track interaction
    function trackInteraction(e) {
        if (!isWatchMode) return;

        const target = e.target;

        // CRITICAL: Exclude WebScope panel elements from capture
        if (target.closest('#ws-panel')) {
            console.log('⏭️ Skipping WebScope panel element:', target.id || target.tagName);
            return;
        }

        // Track INPUT, SELECT, TEXTAREA, and BUTTON elements
        const isFormElement = ['INPUT', 'SELECT', 'TEXTAREA'].includes(target.tagName);
        const isButton = target.tagName === 'BUTTON' ||
                        (target.tagName === 'INPUT' && ['submit', 'button'].includes(target.type));

        if (!isFormElement && !isButton) return;
        if (target.type === 'hidden') return;
        if (!target.offsetParent) return;

        const existing = capturedFields.find(f => f.element === target);

        if (existing) {
            existing.interactions++;
        } else {
            const selectorOptions = generateSelectorOptions(target);
            const defaultSelector = getSelector(target);

            const field = {
                element: target,
                name: target.name || '',
                id: target.id || '',
                type: target.type || (target.tagName === 'BUTTON' ? 'button' : 'text'),
                placeholder: target.placeholder || '',
                selector: defaultSelector,
                selectorOptions: selectorOptions, // All available selector options
                selectedSelector: defaultSelector, // User's choice (initially default)
                category: categorize(target),
                interactions: 1,
                text: target.textContent ? target.textContent.trim() : '' // For buttons
            };

            capturedFields.push(field);
            console.log('✅ Captured:', field.selector, `(${field.category})`, `- ${selectorOptions.length} selector options available`);

            saveSession();

            target.classList.add('ws-highlight');
            setTimeout(() => target.classList.remove('ws-highlight'), 2000);
        }

        if (isActive) renderPanel();
    }

    // Get selector
    function getSelector(el) {
        if (el.id) {
            return '#' + el.id;
        }

        if (el.name) {
            return `${el.tagName.toLowerCase()}[name="${el.name}"]`;
        }

        for (let attr of el.attributes) {
            if (attr.name.startsWith('data-') && attr.value) {
                const selector = `[${attr.name}="${attr.value}"]`;
                if (document.querySelectorAll(selector).length === 1) {
                    return selector;
                }
            }
        }

        const autocomplete = el.getAttribute('autocomplete');
        if (autocomplete && autocomplete !== 'off') {
            const selector = `input[autocomplete="${autocomplete}"]`;
            if (document.querySelectorAll(selector).length <= 2) {
                return selector;
            }
        }

        if (el.placeholder) {
            const selector = `${el.tagName.toLowerCase()}[type="${el.type}"][placeholder="${el.placeholder}"]`;
            if (document.querySelectorAll(selector).length === 1) {
                return selector;
            }
        }

        const ariaLabel = el.getAttribute('aria-label');
        if (ariaLabel) {
            const selector = `[aria-label="${ariaLabel}"]`;
            if (document.querySelectorAll(selector).length === 1) {
                return selector;
            }
        }

        if (el.className && el.className.trim()) {
            const classes = el.className.trim().split(/\s+/);
            for (let cls of classes) {
                const selector = `.${cls}`;
                const matches = document.querySelectorAll(selector);
                if (matches.length === 1) {
                    return selector;
                }
            }
        }

        if (el.type === 'password') {
            const selector = 'input[type="password"]';
            if (document.querySelectorAll(selector).length === 1) {
                return selector;
            }
        }

        const pathWithIds = getSmartPath(el);
        if (pathWithIds) {
            return pathWithIds;
        }

        return getDOMPath(el);
    }

    function getSmartPath(el) {
        let path = [];
        let current = el;

        while (current && current !== document.body) {
            let part = current.tagName.toLowerCase();

            if (current.id) {
                part = '#' + current.id;
                path.unshift(part);
                break;
            }

            if (current.parentElement) {
                const siblings = Array.from(current.parentElement.children).filter(
                    c => c.tagName === current.tagName
                );
                if (siblings.length > 1) {
                    const index = siblings.indexOf(current) + 1;
                    part += `:nth-of-type(${index})`;
                }
            }

            path.unshift(part);
            current = current.parentElement;

            if (path.length >= 5) break;
        }

        const selector = path.join(' > ');
        try {
            if (document.querySelectorAll(selector).length === 1) {
                return selector;
            }
        } catch (e) {
            return null;
        }

        return null;
    }

    function getDOMPath(el) {
        let path = [];
        let current = el;

        while (current && current !== document.body) {
            let part = current.tagName.toLowerCase();
            if (current.id) {
                part += '#' + current.id;
                path.unshift(part);
                break;
            }
            path.unshift(part);
            current = current.parentElement;
        }

        return path.join(' > ');
    }

    // Generate all possible selector options for user choice
    function generateSelectorOptions(el) {
        const options = [];

        // Helper to test if selector is unique
        const isUnique = (selector) => {
            try {
                const matches = document.querySelectorAll(selector);
                return matches.length === 1 && matches[0] === el;
            } catch (e) {
                return false;
            }
        };

        // Option 1: ID selector (if exists) - HIGHEST CONFIDENCE
        if (el.id) {
            const selector = `#${el.id}`;
            if (isUnique(selector)) {
                options.push({
                    selector: selector,
                    label: 'ID',
                    description: `By ID: ${el.id}`,
                    confidence: 95,
                    quality: 'excellent'
                });
            }
        }

        // Option 2: Name attribute (if exists) - HIGH CONFIDENCE
        if (el.name) {
            const tagName = el.tagName.toLowerCase();
            const selector = `${tagName}[name="${el.name}"]`;
            if (isUnique(selector)) {
                options.push({
                    selector: selector,
                    label: 'Name',
                    description: `By name attribute`,
                    confidence: 85,
                    quality: 'good'
                });
            }
        }

        // Option 3: Type attribute (common for inputs) - MEDIUM CONFIDENCE
        if (el.type) {
            const tagName = el.tagName.toLowerCase();
            const selector = `${tagName}[type="${el.type}"]`;
            if (isUnique(selector)) {
                options.push({
                    selector: selector,
                    label: 'Type',
                    description: `By type attribute`,
                    confidence: 70,
                    quality: 'fair'
                });
            }
        }

        // Option 4: Class selector (if unique) - LOWER CONFIDENCE
        if (el.className && typeof el.className === 'string') {
            const classes = el.className.trim().split(/\s+/);
            for (let cls of classes) {
                if (cls) {
                    const selector = `.${cls}`;
                    if (isUnique(selector)) {
                        options.push({
                            selector: selector,
                            label: 'Class',
                            description: `By class: ${cls}`,
                            confidence: 60,
                            quality: 'weak'
                        });
                        break; // Only add first unique class
                    }
                }
            }
        }

        // Option 5: Placeholder (for inputs)
        if (el.placeholder) {
            const tagName = el.tagName.toLowerCase();
            const selector = `${tagName}[placeholder="${el.placeholder}"]`;
            if (isUnique(selector)) {
                options.push({
                    selector: selector,
                    label: 'Placeholder',
                    description: `By placeholder text`
                });
            }
        }

        // Option 6: ARIA label (for accessibility)
        const ariaLabel = el.getAttribute('aria-label');
        if (ariaLabel) {
            const tagName = el.tagName.toLowerCase();
            const selector = `${tagName}[aria-label="${ariaLabel}"]`;
            if (isUnique(selector)) {
                options.push({
                    selector: selector,
                    label: 'ARIA',
                    description: `By aria-label`
                });
            }
        }

        // Option 7: Smart path (CSS path with IDs)
        const smartPath = getSmartPath(el);
        if (smartPath && !options.some(opt => opt.selector === smartPath)) {
            options.push({
                selector: smartPath,
                label: 'Path',
                description: 'CSS path with IDs'
            });
        }

        // Option 8: DOM path (full path)
        const domPath = getDOMPath(el);
        if (domPath && !options.some(opt => opt.selector === domPath)) {
            options.push({
                selector: domPath,
                label: 'Full Path',
                description: 'Full DOM path'
            });
        }

        // If no unique selectors found, use the default selector as fallback
        if (options.length === 0) {
            const fallback = getSelector(el);
            options.push({
                selector: fallback,
                label: 'Auto',
                description: 'Auto-generated selector'
            });
        }

        return options;
    }

    // Categorize field
    function categorize(el) {
        const type = (el.type || '').toLowerCase();
        const tagName = el.tagName.toLowerCase();
        const text = `${el.name} ${el.id} ${el.placeholder} ${el.textContent || ''} ${el.value || ''}`.toLowerCase();
        const ariaLabel = (el.getAttribute('aria-label') || '').toLowerCase();
        const title = (el.getAttribute('title') || '').toLowerCase();
        const allText = `${text} ${ariaLabel} ${title}`;

        // Button detection - more comprehensive
        if (tagName === 'button' || type === 'submit' || type === 'button') {
            // Always categorize as submit - buttons on login pages are submit buttons
            return 'submit';
        }

        if (type === 'password') return 'password';
        if (type === 'email' || /email|mail/.test(allText)) return 'email';
        if (/user|login|account|loginfmt/.test(allText)) return 'username';
        if (/phone|tel|mobile/.test(allText)) return 'phone';
        if (/name|fname|lname/.test(allText)) return 'name';
        if (/2fa|mfa|otp|token|code/.test(allText)) return 'security';
        return 'other';
    }

    // Normalize URL - remove query params and use wildcard for subdomains
    function normalizeURL(url) {
        try {
            const urlObj = new URL(url);
            const hostname = urlObj.hostname;

            // Use wildcard for common auth subdomains
            if (hostname.includes('login.') || hostname.includes('signin.') ||
                hostname.includes('auth.') || hostname.includes('accounts.')) {
                const parts = hostname.split('.');
                const domain = parts.slice(-2).join('.');
                return `*.${domain}`;
            }

            // Return clean URL without query params
            return `${urlObj.protocol}//${hostname}${urlObj.pathname}`.replace(/\/$/, '');
        } catch (e) {
            return url;
        }
    }

    // Detect if this is a multi-step login
    function detectMultiStep() {
        const hasUsername = capturedFields.some(f => f.category === 'username' || f.category === 'email');
        const hasPassword = capturedFields.some(f => f.category === 'password');
        const submitButtons = capturedFields.filter(f => f.category === 'submit');

        // Multi-step if: username+password both exist AND multiple submit buttons
        return hasUsername && hasPassword && submitButtons.length > 1;
    }

    // Generate Keeper RBI
    function generateKeeperRBI() {
        const normalizedPage = normalizeURL(window.location.href);
        const isMultiStep = detectMultiStep();

        const fieldMapping = {
            'username': 'username-field',
            'email': 'username-field',
            'password': 'password-field',
            'security': 'totp-code-field',
            'submit': 'submit'
        };

        if (isMultiStep) {
            // Multi-step: Create separate steps
            const steps = [];

            // Step 1: Username + first submit button
            const step1 = { page: normalizedPage };
            const usernameField = capturedFields.find(f => f.category === 'username' || f.category === 'email');
            const firstSubmit = capturedFields.find(f => f.category === 'submit');

            if (usernameField) step1['username-field'] = usernameField.selectedSelector || usernameField.selector;
            if (firstSubmit) step1['submit'] = firstSubmit.selectedSelector || firstSubmit.selector;
            steps.push(step1);

            // Step 2: Password + second submit button (or first if only one)
            const step2 = { page: normalizedPage };
            const passwordField = capturedFields.find(f => f.category === 'password');
            const submitButtons = capturedFields.filter(f => f.category === 'submit');
            const secondSubmit = submitButtons.length > 1 ? submitButtons[1] : submitButtons[0];

            if (passwordField) step2['password-field'] = passwordField.selectedSelector || passwordField.selector;
            if (secondSubmit) step2['submit'] = secondSubmit.selectedSelector || secondSubmit.selector;
            steps.push(step2);

            return steps;
        } else {
            // Single-step: One config object
            const keeperRBI = { page: normalizedPage };

            capturedFields.forEach(field => {
                const category = field.category.toLowerCase();
                const keeperFieldName = fieldMapping[category];

                if (keeperFieldName && !keeperRBI[keeperFieldName]) {
                    // Use selectedSelector if available, otherwise fall back to default selector
                    keeperRBI[keeperFieldName] = field.selectedSelector || field.selector;
                }
            });

            return [keeperRBI];
        }
    }

    // Generate detailed RBI
    function generateDetailedRBI() {
        const rbi = {
            url: window.location.href,
            domain: window.location.hostname,
            timestamp: new Date().toISOString(),
            fields: {},
            selectors: {}
        };

        capturedFields.forEach(field => {
            const cat = field.category;
            if (!rbi.fields[cat]) rbi.fields[cat] = [];

            rbi.fields[cat].push({
                name: field.name,
                id: field.id,
                type: field.type,
                selector: field.selector,
                placeholder: field.placeholder
            });
        });

        for (const [cat, fields] of Object.entries(rbi.fields)) {
            if (fields.length > 0) {
                rbi.selectors[cat] = fields[0].selector;
            }
        }

        return rbi;
    }

    // Generate Quality Analysis Report
    function generateQualityReport() {
        const report = [];
        const timestamp = new Date().toISOString();
        const currentURL = window.location.href;

        // Header
        report.push('═══════════════════════════════════════════════════════════════');
        report.push('       WEBSCOPE FIELD QUALITY ANALYSIS REPORT');
        report.push('═══════════════════════════════════════════════════════════════');
        report.push('');
        report.push(`Generated: ${timestamp}`);
        report.push(`Source URL: ${currentURL}`);
        report.push(`Extension: WebScope Keeper v4.3.20`);
        report.push('');
        report.push('───────────────────────────────────────────────────────────────');

        // Quality summary
        const qualityCategories = {
            excellent: { count: 0, threshold: 95, label: '⭐ EXCELLENT', fields: [] },
            good: { count: 0, threshold: 85, label: '✅ GOOD', fields: [] },
            fair: { count: 0, threshold: 70, label: '⚠️  FAIR', fields: [] },
            weak: { count: 0, threshold: 0, label: '❌ WEAK', fields: [] }
        };

        // Analyze each field
        capturedFields.forEach((field, idx) => {
            const selectedSelector = field.selectedSelector || field.options[0]?.selector;
            const selectedOption = field.options.find(opt => opt.selector === selectedSelector);
            const confidence = selectedOption?.confidence || 0;

            // Categorize by quality
            if (confidence >= 95) {
                qualityCategories.excellent.count++;
                qualityCategories.excellent.fields.push({ field, idx, confidence, selectedOption });
            } else if (confidence >= 85) {
                qualityCategories.good.count++;
                qualityCategories.good.fields.push({ field, idx, confidence, selectedOption });
            } else if (confidence >= 70) {
                qualityCategories.fair.count++;
                qualityCategories.fair.fields.push({ field, idx, confidence, selectedOption });
            } else {
                qualityCategories.weak.count++;
                qualityCategories.weak.fields.push({ field, idx, confidence, selectedOption });
            }
        });

        // Calculate overall score
        const totalFields = capturedFields.length;
        const overallScore = totalFields > 0
            ? Math.round(
                (qualityCategories.excellent.count * 100 +
                 qualityCategories.good.count * 85 +
                 qualityCategories.fair.count * 70 +
                 qualityCategories.weak.count * 50) / totalFields
              )
            : 0;

        // Summary section
        report.push('');
        report.push('📊 QUALITY SUMMARY');
        report.push('───────────────────────────────────────────────────────────────');
        report.push(`Total Fields Analyzed: ${totalFields}`);
        report.push(`Overall Quality Score: ${overallScore}%`);
        report.push('');
        report.push('Quality Breakdown:');
        report.push(`  ${qualityCategories.excellent.label} (95%+):  ${qualityCategories.excellent.count} fields`);
        report.push(`  ${qualityCategories.good.label} (85-94%): ${qualityCategories.good.count} fields`);
        report.push(`  ${qualityCategories.fair.label} (70-84%): ${qualityCategories.fair.count} fields`);
        report.push(`  ${qualityCategories.weak.label} (<70%):   ${qualityCategories.weak.count} fields`);
        report.push('');

        // Detailed field analysis
        report.push('───────────────────────────────────────────────────────────────');
        report.push('📋 DETAILED FIELD ANALYSIS');
        report.push('───────────────────────────────────────────────────────────────');
        report.push('');

        capturedFields.forEach((field, idx) => {
            const selectedSelector = field.selectedSelector || field.options[0]?.selector;
            const selectedOption = field.options.find(opt => opt.selector === selectedSelector);
            const confidence = selectedOption?.confidence || 0;
            const quality = selectedOption?.quality || 'UNKNOWN';
            const selectorType = selectedOption?.label?.split(' - ')[0] || 'UNKNOWN';

            // Quality indicator
            let indicator = '❌';
            if (confidence >= 95) indicator = '⭐';
            else if (confidence >= 85) indicator = '✅';
            else if (confidence >= 70) indicator = '⚠️';

            report.push(`${indicator} Field ${idx + 1}: ${field.label}`);
            report.push(`   Type: ${field.fieldType}`);
            report.push(`   Confidence: ${confidence}% (${quality})`);
            report.push(`   Selector Type: ${selectorType}`);
            report.push(`   Selector: ${selectedSelector}`);
            report.push(`   Alternatives Available: ${field.options.length}`);
            report.push('');
        });

        // Recommendations
        if (qualityCategories.weak.count > 0 || qualityCategories.fair.count > 0) {
            report.push('───────────────────────────────────────────────────────────────');
            report.push('💡 RECOMMENDATIONS FOR IMPROVEMENT');
            report.push('───────────────────────────────────────────────────────────────');
            report.push('');

            if (qualityCategories.weak.count > 0) {
                report.push(`⚠️  ${qualityCategories.weak.count} WEAK selector(s) detected (<70% confidence)`);
                report.push('');
                qualityCategories.weak.fields.forEach(({ field, idx, selectedOption }) => {
                    const selectorType = selectedOption?.label?.split(' - ')[0] || 'UNKNOWN';
                    report.push(`   • Field ${idx + 1} (${field.label}):`);

                    if (selectorType.includes('Class') || selectorType.includes('Type')) {
                        report.push('     → Consider adding unique ID or name attributes to HTML element');
                        report.push('     → Class and type selectors are less stable across page updates');
                    } else if (selectorType.includes('ARIA')) {
                        report.push('     → ARIA selectors are good but ID/Name would be more stable');
                    }

                    if (field.options.length > 1) {
                        report.push(`     → ${field.options.length} alternative selectors available - review options`);
                    }
                    report.push('');
                });
            }

            if (qualityCategories.fair.count > 0) {
                report.push(`ℹ️  ${qualityCategories.fair.count} FAIR selector(s) detected (70-84% confidence)`);
                report.push('');
                report.push('   These selectors are acceptable but could be improved:');
                qualityCategories.fair.fields.forEach(({ field, idx }) => {
                    report.push(`   • Field ${idx + 1} (${field.label}): Consider using ID-based selector if available`);
                });
                report.push('');
            }

            report.push('General Recommendations:');
            report.push('  1. Prefer ID selectors (95% confidence) over name/type/class');
            report.push('  2. Add unique IDs to form elements for maximum stability');
            report.push('  3. Review alternative selectors for weak fields');
            report.push('  4. Test selectors after any HTML structure changes');
            report.push('');
        } else {
            report.push('───────────────────────────────────────────────────────────────');
            report.push('✅ EXCELLENT QUALITY - No Recommendations Needed');
            report.push('───────────────────────────────────────────────────────────────');
            report.push('');
            report.push('All fields have high-quality selectors (85%+ confidence).');
            report.push('Your form analysis is production-ready!');
            report.push('');
        }

        // Footer
        report.push('───────────────────────────────────────────────────────────────');
        report.push('');
        report.push('📖 UNDERSTANDING CONFIDENCE SCORES:');
        report.push('');
        report.push('  95%+ (ID Selector):    Highly stable, best for production');
        report.push('  85%+ (Name Selector):  Good stability, reliable choice');
        report.push('  70%+ (Type/ARIA):      Acceptable, may need updates');
        report.push('  <70% (Class):          Fragile, likely to break with changes');
        report.push('');
        report.push('───────────────────────────────────────────────────────────────');
        report.push('End of Report');
        report.push('═══════════════════════════════════════════════════════════════');

        return report.join('\n');
    }

    // Export
    function exportRBI() {
        if (capturedFields.length === 0) return;

        const keeperRBI = generateKeeperRBI();
        const keeperJSON = JSON.stringify(keeperRBI, null, 2);

        const detailedRBI = generateDetailedRBI();
        detailedRBI.source = 'WebScope Keeper v4.3.20';
        detailedRBI.fields_count = capturedFields.length;
        const detailedJSON = JSON.stringify(detailedRBI, null, 2);

        // Generate quality analysis report
        const qualityReport = generateQualityReport();

        // Calculate quality summary for alert
        const qualityCounts = { excellent: 0, good: 0, fair: 0, weak: 0 };
        let totalConfidence = 0;
        capturedFields.forEach(field => {
            const selectedSelector = field.selectedSelector || field.options[0]?.selector;
            const selectedOption = field.options.find(opt => opt.selector === selectedSelector);
            const confidence = selectedOption?.confidence || 0;
            totalConfidence += confidence;

            if (confidence >= 95) qualityCounts.excellent++;
            else if (confidence >= 85) qualityCounts.good++;
            else if (confidence >= 70) qualityCounts.fair++;
            else qualityCounts.weak++;
        });
        const overallScore = capturedFields.length > 0
            ? Math.round(totalConfidence / capturedFields.length)
            : 0;

        GM_setClipboard(keeperJSON);

        downloadFile('keeper-rbi-autofill.json', keeperJSON);
        downloadFile('webscope-analysis.json', detailedJSON);
        downloadTextFile('webscope-quality-report.txt', qualityReport);

        alert(`✅ Export Complete!\n\nFields: ${capturedFields.length}\nOverall Quality: ${overallScore}%\n\n📊 Quality Breakdown:\n  ⭐ Excellent: ${qualityCounts.excellent}\n  ✅ Good: ${qualityCounts.good}\n  ⚠️  Fair: ${qualityCounts.fair}\n  ❌ Weak: ${qualityCounts.weak}\n\n📋 Keeper format copied to clipboard\n📥 3 files downloaded:\n  • keeper-rbi-autofill.json\n  • webscope-analysis.json\n  • webscope-quality-report.txt`);

        console.log('🔐 Keeper RBI:', keeperRBI);
        console.log('📊 Detailed Analysis:', detailedRBI);
        console.log('📈 Quality Report Generated:', qualityReport.substring(0, 200) + '...');
    }

    // Download helper for JSON files
    function downloadFile(filename, content) {
        const blob = new Blob([content], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    // Download helper for text files
    function downloadTextFile(filename, content) {
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    // Clear
    function clearCaptured() {
        console.log('🗑️ WebScope: Clearing captured fields...', capturedFields.length);
        capturedFields = [];
        clearHighlights();
        saveSession();  // Clear session storage too
        renderPanel();
        console.log('✅ WebScope: Fields cleared, count now:', capturedFields.length);
    }

    // Clear highlights
    function clearHighlights() {
        document.querySelectorAll('.ws-highlight').forEach(el => {
            el.classList.remove('ws-highlight');
        });
    }

    // Initialize
    init();

})();
